+
+    for (int block = 0; block < BLOCKS_PER_PACKET; block++) {
+      assert(0xEEFF == raw->blocks[block].header);
+      azimuth = (float)(raw->blocks[block].rotation);
+      if (block < (BLOCKS_PER_PACKET-1)){
+        azimuth_diff = (float)((36000 + raw->blocks[block+1].rotation - raw->blocks[block].rotation)%36000);
+        last_azimuth_diff = azimuth_diff;
+      }else{
+        azimuth_diff = last_azimuth_diff;
+      }
+
+      for (int firing=0, k=0; firing < VLP16_FIRINGS_PER_BLOCK; firing++){
+        for (int dsr=0; dsr < VLP16_SCANS_PER_FIRING; dsr++, k+=RAW_SCAN_SIZE){
+          velodyne_pointcloud::LaserCorrection &corrections = 
+            calibration_.laser_corrections[dsr];
+
+          /** Position Calculation */
+          union two_bytes tmp;
+          tmp.bytes[0] = raw->blocks[block].data[k];
+          tmp.bytes[1] = raw->blocks[block].data[k+1];
+          
+          /** correct for the laser rotation as a function of timing during the firings **/
+          azimuth_corrected_f = azimuth + (azimuth_diff * ((dsr*VLP16_DSR_TOFFSET) + (firing*VLP16_FIRING_TOFFSET)) / VLP16_BLOCK_TDURATION);
+          azimuth_corrected = (int)round(fmod(azimuth_corrected_f,36000.0));
+          
+          /*condition added to avoid calculating points which are not
+            in the interesting defined area (min_angle < area < max_angle)*/
+          if ((azimuth_corrected >= config_.min_angle 
+               && azimuth_corrected <= config_.max_angle 
+               && config_.min_angle < config_.max_angle)
+               ||(config_.min_angle > config_.max_angle 
+               && (azimuth_corrected <= config_.max_angle 
+               || azimuth_corrected >= config_.min_angle))){
+            float distance = tmp.uint * DISTANCE_RESOLUTION;
+            distance += corrections.dist_correction;
+            
+            float cos_vert_angle = corrections.cos_vert_correction;
+            float sin_vert_angle = corrections.sin_vert_correction;
+            float cos_rot_correction = corrections.cos_rot_correction;
+            float sin_rot_correction = corrections.sin_rot_correction;
+    
+            // cos(a-b) = cos(a)*cos(b) + sin(a)*sin(b)
+            // sin(a-b) = sin(a)*cos(b) - cos(a)*sin(b)
+            float cos_rot_angle = 
+              cos_rot_table_[azimuth_corrected] * cos_rot_correction + 
+              sin_rot_table_[azimuth_corrected] * sin_rot_correction;
+            float sin_rot_angle = 
+              sin_rot_table_[azimuth_corrected] * cos_rot_correction - 
+              cos_rot_table_[azimuth_corrected] * sin_rot_correction;
+    
+            float horiz_offset = corrections.horiz_offset_correction;
+            float vert_offset = corrections.vert_offset_correction;
+    
+            // Compute the distance in the xy plane (w/o accounting for rotation)
+            float xy_distance = distance * cos_vert_angle;
+    
+            // Calculate temporal X, use absolute value.
+            float xx = xy_distance * sin_rot_angle - horiz_offset * cos_rot_angle;
+            // Calculate temporal Y, use absolute value
+            float yy = xy_distance * cos_rot_angle + horiz_offset * sin_rot_angle;
+            if (xx < 0) xx=-xx;
+            if (yy < 0) yy=-yy;
+      
+            // Get 2points calibration values,Linear interpolation to get distance
+            // correction for X and Y, that means distance correction use
+            // different value at different distance
+            float distance_corr_x = 0;
+            float distance_corr_y = 0;
+            if (corrections.two_pt_correction_available) {
+              distance_corr_x = 
+                (corrections.dist_correction - corrections.dist_correction_x)
+                  * (xx - 2.4) / (25.04 - 2.4) 
+                + corrections.dist_correction_x;
+              distance_corr_x -= corrections.dist_correction;
+              distance_corr_y = 
+                (corrections.dist_correction - corrections.dist_correction_y)
+                  * (yy - 1.93) / (25.04 - 1.93)
+                + corrections.dist_correction_y;
+              distance_corr_y -= corrections.dist_correction;
+            }
+    
+            float distance_x = distance + distance_corr_x;
+            xy_distance = distance_x * cos_vert_angle;
+            x = xy_distance * sin_rot_angle + horiz_offset * cos_rot_angle;
+    
+            float distance_y = distance + distance_corr_y;
+            xy_distance = distance_y * cos_vert_angle;
+            y = xy_distance * cos_rot_angle + horiz_offset * sin_rot_angle;
+    
+            // Using distance_y is not symmetric, but the velodyne manual
+            // does this.
+            z = distance_y * sin_vert_angle + vert_offset;
+  
+    
+            /** Use standard ROS coordinate system (right-hand rule) */
+            float x_coord = y;
+            float y_coord = -x;
+            float z_coord = z;
+    
+            /** Intensity Calculation */
+    
+            float min_intensity = corrections.min_intensity;
+            float max_intensity = corrections.max_intensity;
+    
+            intensity = raw->blocks[block].data[k+2];
+    
+            float focal_offset = 256 
+                               * (1 - corrections.focal_distance / 13100) 
+                               * (1 - corrections.focal_distance / 13100);
+            float focal_slope = corrections.focal_slope;
+            intensity += focal_slope * (abs(focal_offset - 256 * 
+              (1 - tmp.uint/65535)*(1 - tmp.uint/65535)));
+            intensity = (intensity < min_intensity) ? min_intensity : intensity;
+            intensity = (intensity > max_intensity) ? max_intensity : intensity;
+    
+            if (pointInRange(distance)) {
+    
+              // convert polar coordinates to Euclidean XYZ
+              VPoint point;
+              point.ring = corrections.laser_ring;
+              point.x = x_coord;
+              point.y = y_coord;
+              point.z = z_coord;
+              point.intensity = (uint8_t) intensity;
+    
+              // append this point to the cloud
+              pc.points.push_back(point);
+              ++pc.width;
