+float twodDistance(velodyne::laserscan_xyz_t p1, velodyne::laserscan_xyz_t p2){
+  
+  float result;
+  float dx;
+  float dy;
+  
+  dx = p1.x - p2.x;
+  dy = p1.y - p2.y;
+
+  result = sqrt( (dx*dx) + (dy*dy));
+
+  return result;
+}
