+    for(int j = 0; j < CASE_3_LIM; j++){
+      if( j < CASE_1_LIM){
+	if( twodDistance(vect[i][j], vect[i][j+1]) < .03){
+	  if (vect[i][j+1].x < CASE_1_RANGES[j]){
+	    p = vect[i][j+1];
+	    pc.points[pcindex].x = p.x;
+	    pc.points[pcindex].y = p.y;
