+            << "Options:\n"
+            << "\t -h, -?       print usage message\n"
+            << "\t -q <integer> set ROS topic queue depth (default: 1)\n"
+            << std::endl
+            << "Example:\n"
+            << "  rosrun velodyne_example height -q2\n"
+            << std::endl;
+}
