+  if (droppedMsgs)
+    ROS_INFO("total of %u Velodyne messages dropped", droppedMsgs);
+  else
+    ROS_INFO("no Velodyne messages dropped");
+
+  data->shutdown();
+  delete data;
+
+  return 0;
+}
